var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐, 뭐야. 해치웠어......?","JPN":"な、何なの、始末できたというのですか……？","ENG":"H-how is that possible? You wiped them out so easily!","TWN":"什，什麼。解決掉了嗎……？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잔챙이들은 대부분 처리한 것 같네요, 스승님.","JPN":"雑魚どもはだいたい片付いたみたいですね、師匠。","ENG":"We took care of most small fry, Master.","TWN":"師父，看來那些雜魚被收拾的差不多了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 이제 곧 나타나겠군.","JPN":"ああ、じきに奴が現れそうだ。","ENG":"We did. Our real prey will show up soon.","TWN":"好。應該馬上就要出現了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잔챙이라니......","JPN":"雑魚どもって……","ENG":"Small fry?","TWN":"竟然說是雜魚……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이것들 하나하나가...... 우리 세계에선 국가의 존속을 위협하는 괴물들인데......","JPN":"それぞれの個体が……私たちの世界では、国の存続を脅かす化け物だというのに……","ENG":"Each and every single one of them could have threatened the existence of a country in our world.","TWN":"它們每一個……在我們的世界裡，都是威脅到國家存亡的怪物啊……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"차원 통로로부터 흘러나오는 힘이 강해지고 있다.","JPN":"次元間通路から流れ出る力が強まっている。","ENG":"The energy leaking from the dimensional passageway is growing stronger.","TWN":"從次元通道流出的力量越來越強。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"사냥감이 가까이 오고 있나 보군. 준비해라.","JPN":"獲物が近づいてきてる、構えろ。","ENG":"The Prey is near. Get ready.","TWN":"看來獵物接近了。做好準備。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등급은 어느 정도죠?","JPN":"ランクはどのくらいです？","ENG":"To which category do you think it belongs?","TWN":"等級大概是？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"느껴지는 수준은 4종 중급 침식체 정도군.","JPN":"第4種の中級侵食体程度だな。","ENG":"As far as I can tell, Category 4. Middle class.","TWN":"憑感覺來看，應該是第4級的中級侵蝕體。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"확실한 건 직접 봐야 알겠지만.","JPN":"直接見てみないと確信はできないがな。","ENG":"I won't know until I see it, though.","TWN":"雖然得親眼看到才能確認。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 인자를 가진 사냥감치고는 무난한 편이군요.","JPN":"クリフォト・ファクター所持の獲物にしては無難なほうですね。","ENG":"It wouldn't be too difficult for Prey with the Qliphoth Factor.","TWN":"以擁有逆卡巴拉因子的獵物來說，還算過得去。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"항상 하던 대로 스승님이 전방을, 제가 지원을 맡으면 될까요?","JPN":"いつも通り、師匠は前方、僕は支援担当でいいですか？","ENG":"Are we doing what we always do, you at the front and me in the rear?","TWN":"那就像往常一樣，師父負責前方，我負責支援嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇긴 한데...... 생각보다 침식체들이 많이 몰려오는군.","JPN":"それでいいが……思ったよりも侵食体の数が多いぞ。","ENG":"Sure, but we're getting more C.O.s than I thought.","TWN":"但是這……聚集的侵蝕體比想像來得還要多。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주변에 방해꾼들이 많다면 우리 둘만으로는 조금 귀찮아질 수도 있겠어.","JPN":"周辺に邪魔者が多い場合は、私たちだけじゃ少し手こずるかもしれないな。","ENG":"Having too many of them can get in our way of hunting the Prey.","TWN":"周圍妨礙者太多的話，光靠我們兩個可能會有些麻煩。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......거기!","JPN":"……そこ！","ENG":"Hey, illegal dumpers over there.","TWN":"……喂！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓰레기 무단투기꾼 아가씨들은 어떻게 할지 정했나?","JPN":"ゴミの不法投棄にきた小娘たち。どうするか決めたのか？","ENG":"Have you decided what you want to do?","TWN":"隨便傾倒垃圾的小姐，你們決定好要怎麼做了嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"정말로...... 놈을 쓰러트릴 수 있는 건가요? 그 끔찍한 괴물을?","JPN":"本当に……奴を倒せるんですか？　あの忌々しい化け物を？","ENG":"Can you... Can you really bring it down? That terrible monster?","TWN":"真的……可以打倒它們嗎？打倒那可怕的怪物？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};